const streamUrl = "http://151.243.169.248/radio/8000/radio.mp3";
const apiUrl = "http://151.243.169.248/api/nowplaying/radiosebastian";

const audio = document.getElementById('stream');
const btn = document.getElementById('play-btn');
const icon = document.getElementById('play-icon');
const rsLogo = document.getElementById('rsLogo');
const volSlider = document.getElementById('vol-slider');
const songTitle = document.getElementById('song-title');

btn.onclick = function() {
    if (audio.paused) {
        audio.src = streamUrl + "?ts=" + Date.now();
        audio.play();
        icon.className = 'fas fa-pause';
        rsLogo.style.animationPlayState = 'running';
    } else {
        audio.pause();
        audio.src = "";
        icon.className = 'fas fa-play';
        rsLogo.style.animationPlayState = 'paused';
    }
};

volSlider.oninput = () => audio.volume = volSlider.value;

async function updateRadio() {
    try {
        const res = await fetch(apiUrl);
        const data = await res.json();
        const song = data.now_playing.song;

        if (song.artist && song.title) {
            songTitle.innerText = song.artist + " - " + song.title;
        } else {
            songTitle.innerText = song.text || "Rádio Sebastián - živě";
        }

    } catch {
        songTitle.innerText = "Bez připojení";
    }
}

updateRadio();
setInterval(updateRadio, 10000);

